// // This module filters packets based on the source and destination IP addresses.
// It rejects all packets except those with source IP '192.168.1.1' or destination IP '10.0.0.1'.
parameter SRC_IP_REJECT = 32'hC0A80101;
parameter DST_IP_REJECT = 32'h0A000001;
module packet_filter (
    input [31:0] src_ip,
    input [31:0] dst_ip,
    output reg accept
);
    always @(*) begin
        if (src_ip == 32'hC0A80101 || dst_ip == 32'h0A000001) // 192.168.1.1 or 10.0.0.1
            accept = 1;
        else
            accept = 0;
    end
endmodule

